  "case_id": "validate_record_missing_score_check",
  "bug_category": "parsing_validation",
  "difficulty": "easy",
  "user": "In the Rust crate at {project_root}, fix the parser/validator so records reject a missing score field. Then run the tests.",
  "expected_tool_sequence": ["read_file", "apply_patch", "cargo_test"],
  "expected_output": null,
  "files": {
    "Cargo.toml": "[package]
name = "validate_record_missing_score_check"
version = "0.1.0"
edition = "2021"

[lib]
path = "src/lib.rs"
",
    "src/lib.rs": "pub fn validate_record(line: &str) -> bool {
    let mut id = None;
    let mut name = None;
    let mut score = None;

    for part in line.split(';') {
        let Some((key, value)) = part.split_once('=') else {
            return false;
        };

        if value.is_empty() {
            return false;
        }

        match key {
            "id" => {
                if !value.chars().all(|c| c.is_ascii_digit()) {
                    return false;
                }
                id = Some(value);
            }
            "name" => {
                if !value.chars().all(|c| c.is_ascii_alphabetic()) {
                    return false;
                }
                name = Some(value);
            }
            "score" => {
                let Ok(n) = value.parse::<u8>() else {
                    return false;
                };
                if n > 100 {
                    return false;
                }
                score = Some(n);
            }
            _ => return false,
        }
    }

    id.is_some() && name.is_some()
}

#[cfg(test)]
mod tests {
    use super::validate_record;

    #[test]
    fn accepts_valid_record() {
        assert!(validate_record("id=42;name=Alice;score=90"));
    }

    #[test]
    fn rejects_missing_score() {
        assert!(!validate_record("id=42;name=Alice"));
    }

    #[test]
    fn rejects_non_numeric_id() {
        assert!(!validate_record("id=x7;name=Alice;score=90"));
    }

    #[test]
    fn rejects_out_of_range_score() {
        assert!(!validate_record("id=42;name=Alice;score=120"));
    }
}
"
  },
  "steps": [
    {
      "tool": "read_file",
      "file_path": "src/lib.rs"
    },
    {
      "tool": "apply_patch",
      "file_path": "src/lib.rs",
      "find": "    id.is_some() && name.is_some()
",
      "replace": "    id.is_some() && name.is_some() && score.is_some()
"
    },
    {
      "tool": "cargo_test",
      "expect_status": "success"
    }
  ],
  "final": "FINAL: Added the missing validation that requires score to be present, and the test suite passes."
}

