      "find": "    items.sort_by(|a, b| {
        a.score
            .cmp(&b.score)
            .then(a.penalties.cmp(&b.penalties))
            .then(a.name.cmp(&b.name))
    });
",
      "replace": "    items.sort_by(|a, b| {
        b.score
            .cmp(&a.score)
            .then(a.penalties.cmp(&b.penalties))
            .then(a.name.cmp(&b.name))
    });
"
    },
    {
