    "src/lib.rs": "use std::collections::BTreeMap;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Sale {
    pub region: &'static str,
    pub month: u8,
    pub amount: i32,
    pub refunded: bool,
}

pub fn monthly_region_report(sales: &[Sale], month: u8) -> String {
    let mut totals: BTreeMap<&str, (usize, i32)> = BTreeMap::new();

    for sale in sales {
        if sale.month != month || sale.refunded {
            continue;
        }
        let entry = totals.entry(sale.region).or_insert((0, 0));
        entry.0 += 1;
        entry.1 += sale.amount;
    }

    let mut rows: Vec<_> = totals.into_iter().collect();
    rows.sort_by(|a, b| b.1 .1.cmp(&a.1 .1).then_with(|| a.0.cmp(b.0)));

    let mut out = format!("month={month}");
    for (region, (orders, revenue)) in rows {
        if revenue == 0 {
            continue;
        }
        out.push_str(&format!("\n{region}: orders={orders}, revenue={revenue}"));
    }
    out
}

#[cfg(test)]
mod tests {
    use super::*;

    fn sample_sales() -> Vec<Sale> {
        vec![
            Sale { region: "west", month: 3, amount: 80, refunded: false },
            Sale { region: "east", month: 3, amount: 120, refunded: false },
            Sale { region: "west", month: 3, amount: 20, refunded: true },
            Sale { region: "north", month: 3, amount: 0, refunded: false },
            Sale { region: "east", month: 2, amount: 75, refunded: false },
            Sale { region: "south", month: 3, amount: 80, refunded: false },
            Sale { region: "south", month: 3, amount: -10, refunded: false },
            Sale { region: "north", month: 4, amount: 50, refunded: false },
        ]
    }

    #[test]
    fn report_filters_month_and_refunds_and_sorts() {
        let report = monthly_region_report(&sample_sales(), 3);
        assert_eq!(
            report,
            "month=3\neast: orders=1, revenue=120\nsouth: orders=2, revenue=70\nwest: orders=1, revenue=80\nnorth: orders=1, revenue=0"
        );
    }

    #[test]
    fn report_with_no_matching_sales_is_header_only() {
        let report = monthly_region_report(&sample_sales(), 9);
        assert_eq!(report, "month=9");
    }
}
"
  },
  "steps": [
    {
      "tool": "read_file",
      "file_path": "src/lib.rs"
    },
    {
      "tool": "apply_patch",
      "file_path": "src/lib.rs",
      "find": "    let mut rows: Vec<_> = totals.into_iter().collect();
    rows.sort_by(|a, b| b.1 .1.cmp(&a.1 .1).then_with(|| a.0.cmp(b.0)));

    let mut out = format!("month={month}");
    for (region, (orders, revenue)) in rows {
        if revenue == 0 {
            continue;
        }
        out.push_str(&format!("\n{region}: orders={orders}, revenue={revenue}"));
    }
",
      "replace": "    let mut rows: Vec<_> = totals.into_iter().collect();
    rows.sort_by(|a, b| {
        b.1 .1
            .cmp(&a.1 .1)
            .then_with(|| b.1 .0.cmp(&a.1 .0))
            .then_with(|| a.0.cmp(b.0))
    });

    let mut out = format!("month={month}");
    for (region, (orders, revenue)) in rows {
        out.push_str(&format!("\n{region}: orders={orders}, revenue={revenue}"));
    }
"
    },
    {
      "tool": "cargo_test",
      "expect_status": "success"
