pub struct RankedPlayer {
    pub rank: usize,
    pub name: String,
    pub score: u32,
    pub penalties: u32,
}

pub fn rank_players(players: &[Player]) -> Vec<RankedPlayer> {
    let mut items = players.to_vec();
    items.sort_by(|a, b| {
        b.score
            .cmp(&a.score)
            .then_with(|| a.name.cmp(&b.name))
            .then_with(|| a.penalties.cmp(&b.penalties))
    });

    let mut out = Vec::with_capacity(items.len());
    let mut current_rank = 1;

    for (idx, p) in items.into_iter().enumerate() {
        if idx > 0 {
            let prev = &out[idx - 1];
            if prev.score != p.score || prev.penalties != p.penalties {
                current_rank = idx + 1;
            }
        }

        out.push(RankedPlayer {
            rank: current_rank,
            name: p.name,
            score: p.score,
            penalties: p.penalties,
