#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum State {
    Todo,
    InProgress,
    Blocked,
    Done,
    Rejected,
}

impl State {
    fn as_str(self) -> &'static str {
        match self {
            State::Todo => "Todo",
            State::InProgress => "InProgress",
            State::Blocked => "Blocked",
            State::Done => "Done",
            State::Rejected => "Rejected",
        }
    }
}

enum Event {
    Start,
    Block,
    Unblock,
    Finish,
    Reopen,
    Reject,
}

struct Ticket {
    state: State,
    blockers: u32,
}

impl Ticket {
    fn new() -> Self {
        Self {
            state: State::Todo,
            blockers: 0,
        }
    }

    fn apply(&mut self, event: Event) {
        match event {
            Event::Start => {
                if self.state == State::Todo {
                    self.state = State::InProgress;
                }
            }
            Event::Block => {
                self.blockers += 1;
                self.state = State::Blocked;
            }
            Event::Unblock => {
                if self.blockers > 0 {
                    self.blockers -= 1;
                }
                self.state = State::Todo;
            }
            Event::Finish => {
                if self.state != State::Rejected {
                    self.state = State::Done;
                }
            }
            Event::Reopen => {
                self.state = State::Todo;
            }
            Event::Reject => {
                self.state = State::Rejected;
            }
        }
    }
}

