}

pub fn merge_config(
    defaults: &Config,
    file: Option<&PartialConfig>,
    env: Option<&PartialConfig>,
    cli: Option<&PartialConfig>,
) -> Config {
    let mut merged = defaults.clone();

    for layer in [file, env, cli] {
        if let Some(cfg) = layer {
            if let Some(endpoint) = &cfg.endpoint {
                merged.endpoint = endpoint.clone();
            }
            if let Some(timeout_ms) = cfg.timeout_ms {
                merged.timeout_ms = timeout_ms;
            }
            if let Some(retries) = cfg.retries {
                merged.retries = retries;
            }
            if let Some(feature_enabled) = cfg.feature_enabled {
