pub fn conflicts(existing: &[Booking], candidate: Booking) -> bool {
    existing.iter().any(|b| {
        (candidate.start >= b.start && candidate.start <= b.end)
            || (candidate.end >= b.start && candidate.end <= b.end)
    })
}

