",
    "src/lib.rs": "use std::collections::BTreeMap;

#[derive(Debug, Clone, Copy)]
pub struct Event {
    pub team: &'static str,
    pub points: i32,
    pub penalty: bool,
    pub active: bool,
}

pub fn build_report(events: &[Event]) -> String {
    let mut totals: BTreeMap<&str, (i32, usize)> = BTreeMap::new();

    for e in events {
        if !e.active {
            continue;
        }
        let entry = totals.entry(e.team).or_insert((0, 0));
        entry.0 += e.points;
        entry.1 += 1;
    }

    let mut rows: Vec<(&str, i32, usize)> = totals
        .into_iter()
        .map(|(team, (points, count))| (team, points, count))
        .collect();

    rows.sort_by(|a, b| a.0.cmp(b.0));

    let mut out = String::new();
    for (team, points, count) in rows {
        out.push_str(&format!("{}:{}:{}\n", team, points, count));
    }
    out
}

