            Event { team: "beta", points: 2, penalty: true, active: true },
            Event { team: "gamma", points: 7, penalty: false, active: false },
            Event { team: "alpha", points: -5, penalty: false, active: true },
            Event { team: "delta", points: 0, penalty: false, active: true },
            Event { team: "beta", points: -1, penalty: false, active: true },
        ];

        let report = build_report(&events);
        assert_eq!(
