    "src/lib.rs": "#[derive(Debug, Clone, PartialEq, Eq)]
pub enum Request {
    Ping,
    Fetch { key: String, cached: bool },
    Mutate { dry_run: bool },
    Admin(AdminAction),
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub enum AdminAction {
    FlushCache,
    RotateKeys,
    Audit { verbose: bool },
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub enum Route {
    Local,
    Cache,
    Write,
    Control,
    Deny,
}

pub fn decide(req: &Request, readonly_mode: bool, allow_admin: bool) -> Route {
    match req {
        Request::Ping => Route::Local,
        Request::Fetch { cached, .. } => {
            if *cached {
                Route::Cache
            } else {
                Route::Write
            }
        }
        Request::Mutate { dry_run } => {
            if readonly_mode || *dry_run {
                Route::Local
            } else {
                Route::Write
            }
        }
        Request::Admin(action) => match action {
            AdminAction::FlushCache => {
                if allow_admin {
                    Route::Control
                } else {
                    Route::Deny
                }
            }
            AdminAction::RotateKeys => Route::Control,
            AdminAction::Audit { verbose } => {
                if *verbose {
                    Route::Control
                } else {
                    Route::Local
                }
            }
        },
    }
}

