        Cmd::Copy {
            from: "a.txt",
            to: "backup/a.txt",
        },
        Cmd::Delete {
            path: "temp.log",
            permanent: true,
        },
        Cmd::Move {
            src: "src/lib.rs",
            dst: "archive/lib.rs",
        },
        Cmd::Unknown("deploy"),
    ];

    for cmd in cmds.iter() {
