    "src/main.rs": "use std::collections::BTreeMap;

#[derive(Clone, Copy, PartialEq, Eq)]
enum State {
    Open,
    InProgress,
    Resolved,
    Closed,
    Reopened,
}

impl State {
    fn as_str(self) -> &'static str {
        match self {
            State::Open => "Open",
            State::InProgress => "InProgress",
            State::Resolved => "Resolved",
            State::Closed => "Closed",
            State::Reopened => "Reopened",
        }
    }
}

fn apply_event(state: State, event: &str) -> State {
    match event {
        "start" => State::InProgress,
        "resolve" => State::Resolved,
        "close" => State::Closed,
        "reopen" => State::Open,
        _ => state,
    }
}

fn main() {
    let events = [
        ("A", "start"),
        ("A", "resolve"),
        ("A", "close"),
        ("B", "start"),
        ("B", "resolve"),
        ("B", "reopen"),
        ("C", "close"),
        ("C", "reopen"),
        ("C", "resolve"),
        ("C", "close"),
    ];

    let mut states: BTreeMap<&str, State> = BTreeMap::new();
    for (ticket, event) in events {
        let current = *states.get(ticket).unwrap_or(&State::Open);
        let next = apply_event(current, event);
        states.insert(ticket, next);
    }

    for (ticket, state) in states {
        println!("{}:{}", ticket, state.as_str());
    }
}
